import{_ as r,C as a,o as i,c as n,E as o,w as d,a as s,a0 as l}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Ireland Healthcare & HRT","description":"Transgender healthcare access in Ireland","frontmatter":{"layout":"doc","title":"Ireland Healthcare & HRT","description":"Transgender healthcare access in Ireland"},"headers":[],"relativePath":"europe/ireland/healthcare.md","filePath":"europe/ireland/healthcare.md","lastUpdated":null}'),h={name:"europe/ireland/healthcare.md"};function c(p,e,u,m,b,g){const t=a("Badge");return i(),n("div",null,[o(t,{variant:"yellow"},{default:d(()=>[...e[0]||(e[0]=[s("Gatekeeping (Improving)",-1)])]),_:1}),e[1]||(e[1]=l('<h1 id="healthcare-hrt-in-ireland" tabindex="-1">Healthcare &amp; HRT in Ireland <a class="header-anchor" href="#healthcare-hrt-in-ireland" aria-label="Permalink to &quot;Healthcare &amp; HRT in Ireland&quot;">​</a></h1><h2 id="access-model" tabindex="-1">Access Model <a class="header-anchor" href="#access-model" aria-label="Permalink to &quot;Access Model&quot;">​</a></h2><p>Ireland operates a gatekeeping model for transgender healthcare. The primary public pathway is through the National Gender Service (NGS) in Dublin, which requires a referral from a GP followed by a lengthy assessment process. Wait times for a first appointment at the NGS have historically been 3-5 years, though recent reforms aim to reduce this.</p><p>Alternatives include private endocrinologists who may prescribe under informed consent, and the GenderGP service (online, UK-based). Some GPs are willing to prescribe HRT under shared care agreements with private specialists.</p><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>National Gender Service (NGS)</td><td>Dublin</td><td>Public gender clinic, HRT, surgery referrals</td></tr><tr><td>GenderGP</td><td>Online</td><td>Remote HRT prescribing, international</td></tr><tr><td>Private Endos (Various)</td><td>Dublin, Cork</td><td>Private HRT, shorter wait times</td></tr><tr><td>TENI Healthcare Directory</td><td>Nationwide</td><td>Trans-friendly GP listings</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>As an EU member, Ireland recognises prescriptions from other EU/EEA countries. Non-EU arrivals need an Irish doctor to convert their prescription. A medical history in English is essential. Many GPs listed with TENI are familiar with transgender healthcare.</p><p>A 3-month supply of HRT for personal use is generally permitted with a valid prescription. Note that Ireland has strict medicine import regulations — check with the HPRA before moving larger quantities.</p><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender-affirming surgeries are available through the NGS with public funding, but wait times are very long (3-5+ years). Many Irish trans people travel abroad for surgery (UK, Belgium, Germany, Thailand). Some surgeries may be covered under the EU Cross-Border Healthcare Directive.</p><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Public Cost</th><th>Private Cost</th></tr></thead><tbody><tr><td>GP visit</td><td>Free (with GP Visit Card)</td><td>€50-80</td></tr><tr><td>Endocrinologist</td><td>€50-80 (public)</td><td>€150-300</td></tr><tr><td>HRT (monthly)</td><td>€15-40</td><td>€40-80</td></tr><tr><td>Top Surgery</td><td>Covered (NGS, long wait)</td><td>€6,000-12,000</td></tr><tr><td>Bottom Surgery</td><td>Covered (NGS, long wait)</td><td>€20,000-40,000</td></tr></tbody></table>',13))])}const v=r(h,[["render",c]]);export{f as __pageData,v as default};
